// Deep Link Configuration
class DeepLinkConfig {
  static const String scheme = 'myapp';
  static const Set<String> allowedHosts = {
    'profile',
    'payment',
    'settings',
    'home',
  };

  static const Set<String> allowedPaymentActions = {
    'confirm',
    'cancel',
    'status',
  };

  static const int maxParameterLength = 256;
  static const int maxIdLength = 64;

  // Allowed characters for IDs (alphanumeric, hyphens, underscores)
  static final RegExp validIdPattern = RegExp(r'^[a-zA-Z0-9_-]+$');
  static final RegExp validActionPattern = RegExp(r'^[a-zA-Z0-9_-]+$');
}

// Parsed deep link model
class DeepLinkData {
  final String path;
  final Map<String, String> parameters;
  final String? host;
  final List<String> pathSegments;

  const DeepLinkData({
    required this.path,
    required this.parameters,
    this.host,
    required this.pathSegments,
  });

  @override
  String toString() =>
      'DeepLinkData(path: $path, host: $host, segments: $pathSegments, params: $parameters)';
}

// Deep Link Parser with security validation
class DeepLinkParser {
  /// Parses and validates a deep link URI
  /// Returns null if the URI is invalid or potentially malicious
  static DeepLinkData? parse(Uri uri) {
    // Validate scheme
    if (uri.scheme != DeepLinkConfig.scheme) {
      debugPrint('DeepLinkParser: Invalid scheme: ${uri.scheme}');
      return null;
    }

    // Validate host
    final host = uri.host.isNotEmpty ? uri.host : _extractHost(uri);
    if (host == null || !DeepLinkConfig.allowedHosts.contains(host)) {
      debugPrint('DeepLinkParser: Invalid or disallowed host: $host');
      return null;
    }

    // Extract and validate path segments
    final pathSegments = uri.pathSegments
        .where((s) => s.isNotEmpty)
        .map((s) => _sanitizeSegment(s))
        .whereType<String>()
        .toList();

    // Validate query parameters
    final sanitizedParams = <String, String>{};
    for (final entry in uri.queryParameters.entries) {
      final key = _sanitizeParameter(entry.key);
      final value = _sanitizeParameter(entry.value);
      if (key != null && value != null) {
        sanitizedParams[key] = value;
      }
    }

    return DeepLinkData(
      path: uri.path,
      parameters: sanitizedParams,
      host: host,
      pathSegments: pathSegments,
    );
  }

  static String? _extractHost(Uri uri) {
    // For URIs like myapp://profile/123, host might be in path
    final path = uri.path;
    if (path.startsWith('//')) {
      final segments = path.substring(2).split('/');
      if (segments.isNotEmpty) return segments.first;
    }
    // Sometimes uni_links parses myapp://profile/123 with host='profile'
    if (uri.host.isNotEmpty) return uri.host;
    if (uri.pathSegments.isNotEmpty) return uri.pathSegments.first;
    return null;
  }

  static String? _sanitizeSegment(String segment) {
    if (segment.length > DeepLinkConfig.maxParameterLength) return null;
    if (!DeepLinkConfig.validIdPattern.hasMatch(segment)) return null;
    return segment;
  }

  static String? _sanitizeParameter(String value) {
    if (value.length > DeepLinkConfig.maxParameterLength) return null;
    // Strip any potential injection characters
    final sanitized = value.replaceAll(RegExp(r'[<>"\x27;(){}]'), '');
    if (sanitized.isEmpty) return null;
    return sanitized;
  }
}

// Route definitions
class AppRoutes {
  static const String home = '/';
  static const String profile = '/profile';
  static const String paymentConfirm = '/payment/confirm';
  static const String paymentStatus = '/payment/status';
  static const String paymentCancel = '/payment/cancel';
  static const String notFound = '/not-found';
