// Deep Link Handler Service
class DeepLinkHandler {
  final GlobalKey<NavigatorState> navigatorKey;
  StreamSubscription? _linkSubscription;
  bool _isInitialized = false;

  // Rate limiting
  DateTime? _lastDeepLinkTime;
  int _deepLinkCount = 0;
  static const int _maxDeepLinksPerMinute = 10;
  static const Duration _rateLimitWindow = Duration(minutes: 1);

  DeepLinkHandler({required this.navigatorKey});

  /// Initialize deep link handling
  Future<void> initialize() async {
    if (_isInitialized) return;
    _isInitialized = true;

    // Handle initial deep link (app opened via deep link)
    await _handleInitialLink();

    // Handle deep links while app is running
    _linkSubscription = uriLinkStream.listen(
      _handleIncomingLink,
      onError: (error) {
        debugPrint('DeepLinkHandler: Stream error: $error');
      },
    );
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialUri = await getInitialUri();
      if (initialUri != null) {
        _processUri(initialUri);
      }
    } catch (e) {
      debugPrint('DeepLinkHandler: Error getting initial link: $e');
    }
  }

  void _handleIncomingLink(Uri? uri) {
    if (uri != null) {
      _processUri(uri);
    }
  }

  void _processUri(Uri uri) {
    // Rate limiting check
    if (!_checkRateLimit()) {
      debugPrint('DeepLinkHandler: Rate limit exceeded, ignoring deep link');
      return;
    }

    debugPrint('DeepLinkHandler: Processing URI: $uri');

    final deepLinkData = DeepLinkParser.parse(uri);
    if (deepLinkData == null) {
      debugPrint('DeepLinkHandler: Failed to parse or validate URI');
      _navigateTo(AppRoutes.notFound);
      return;
    }

    _routeDeepLink(deepLinkData);
  }

  bool _checkRateLimit() {
    final now = DateTime.now();
    if (_lastDeepLinkTime == null ||
        now.difference(_lastDeepLinkTime!) > _rateLimitWindow) {
      _lastDeepLinkTime = now;
      _deepLinkCount = 1;
      return true;
    }
    _deepLinkCount++;
    return _deepLinkCount <= _maxDeepLinksPerMinute;
  }

  void _routeDeepLink(DeepLinkData data) {
    final host = data.host;
    final segments = data.pathSegments;

    switch (host) {
      case 'profile':
        _handleProfileLink(segments, data.parameters);
        break;
      case 'payment':
        _handlePaymentLink(segments, data.parameters);
        break;
      case 'home':
        _navigateTo(AppRoutes.home);
        break;
      default:
        debugPrint('DeepLinkHandler: Unhandled host: $host');
        _navigateTo(AppRoutes.notFound);
    }
  }

  void _handleProfileLink(
      List<String> segments, Map<String, String> parameters) {
    // myapp://profile/123 or myapp://profile?id=123
    String? profileId;

    if (segments.isNotEmpty) {
      profileId = segments.first;
    } else if (parameters.containsKey('id')) {
      profileId = parameters['id'];
    }

    // Validate profile ID
    if (profileId == null || profileId.length > DeepLinkConfig.maxIdLength) {
      debugPrint('DeepLinkHandler: Invalid profile ID');
      _navigateTo(AppRoutes.notFound);
      return;
    }

    if (!DeepLinkConfig.validIdPattern.hasMatch(profileId)) {
      debugPrint('DeepLinkHandler: Profile ID contains invalid characters');
      _navigateTo(AppRoutes.notFound);
      return;
    }

    _navigateTo(AppRoutes.profile, arguments: {'profileId': profileId});
  }

  void _handlePaymentLink(
      List<String> segments, Map<String, String> parameters) {
    // myapp://payment/confirm?txn=abc123
    if (segments.isEmpty) {
      debugPrint('DeepLinkHandler: Payment link missing action');
      _navigateTo(AppRoutes.notFound);
      return;
    }

    final action = segments.first;

    // Validate action against allowed list
    if (!DeepLinkConfig.allowedPaymentActions.contains(action)) {
      debugPrint('DeepLinkHandler: Invalid payment action: $action');
      _navigateTo(AppRoutes.notFound);
      return;
    }

    // Validate transaction ID if present
    final transactionId = parameters['txn'] ?? parameters['transaction_id'];
    if (transactionId != null) {
      if (transactionId.length > DeepLinkConfig.maxIdLength ||
          !DeepLinkConfig.validIdPattern.hasMatch(transactionId)) {
        debugPrint('DeepLinkHandler: Invalid transaction ID');
        _navigateTo(AppRoutes.notFound);
        return;
      }
    }

    switch (action) {
      case 'confirm':
        _navigateTo(AppRoutes.paymentConfirm, arguments: {
          'transactionId': transactionId,
          ...parameters,
        });
        break;
      case 'status':
        _navigateTo(AppRoutes.paymentStatus, arguments: {
          'transactionId': transactionId,
          ...parameters,
        });
        break;
      case 'cancel':
        _navigateTo(AppRoutes.paymentCancel, arguments: {
          'transactionId': transactionId,
          ...parameters,
        });
        break;
    }
  }

  void _navigateTo(String route, {Map<String, String?>? arguments}) {
    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('DeepLinkHandler: Navigator not available');
      return;
    }

    // Use pushNamedAndRemoveUntil to prevent deep link stacking attacks
    navigator.pushNamedAndRemoveUntil(
      route,
      (route) => route.isFirst,
      arguments: arguments,
    );
  }

  void dispose() {
    _linkSubscription?.cancel();
    _linkSubscription = null;
    _isInitialized = false;
  }
}

