// --- Main App ---

class DeepLinkApp extends StatefulWidget {
  const DeepLinkApp({super.key});

  @override
  State<DeepLinkApp> createState() => _DeepLinkAppState();
}

class _DeepLinkAppState extends State<DeepLinkApp> {
  final GlobalKey<NavigatorState> _navigatorKey = GlobalKey<NavigatorState>();
  late final DeepLinkHandler _deepLinkHandler;

  @override
  void initState() {
    super.initState();
    _deepLinkHandler = DeepLinkHandler(navigatorKey: _navigatorKey);
    _deepLinkHandler.initialize();
  }

  @override
  void dispose() {
    _deepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Deep Link Demo',
      navigatorKey: _navigatorKey,
      theme: ThemeData(
        colorSchemeSeed: Colors.blue,
        useMaterial3: true,
      ),
      initialRoute: AppRoutes.home,
      onGenerateRoute: _onGenerateRoute,
      onUnknownRoute: (settings) => MaterialPageRoute(
        builder: (_) => const NotFoundScreen(),
        settings: settings,
      ),
    );
  }

  Route<dynamic>? _onGenerateRoute(RouteSettings settings) {
    switch (settings.name) {
      case AppRoutes.home:
        return MaterialPageRoute(
          builder: (_) => const HomeScreen(),
          settings: settings,
        );
      case AppRoutes.profile:
        return MaterialPageRoute(
          builder: (_) => const ProfileScreen(),
          settings: settings,
        );
      case AppRoutes.paymentConfirm:
        return MaterialPageRoute(
          builder: (_) => const PaymentConfirmScreen(),
          settings: settings,
        );
      case AppRoutes.paymentStatus:
        return MaterialPageRoute(
          builder: (_) => const PaymentStatusScreen(),
          settings: settings,
        );
      case AppRoutes.paymentCancel:
        return MaterialPageRoute(
          builder: (_) => const PaymentCancelScreen(),
          settings: settings,
        );
      case AppRoutes.notFound:
        return MaterialPageRoute(
          builder: (_) => const NotFoundScreen(),
          settings: settings,
        );
      default:
        return MaterialPageRoute(
          builder: (_) => const NotFoundScreen(),
          settings: settings,
        );
    }
  }
}

void main() {
  WidgetsFlutterBinding.ensureInitialized();
  runApp(const DeepLinkApp());
}